Code.Terraform:
```hcl
# Terraform: AppStream フリートでデフォルトのインターネットアクセスを無効にします
resource "aws_appstream_fleet" "<example_resource_name>" {
  name          = "<example_resource_name>"
  instance_type = "stream.standard.small"
  image_name    = "<IMAGE_NAME>"
  compute_capacity { desired_instances = 1 }

  enable_default_internet_access = false  # 重要：デフォルトのインターネットアクセスを無効にしてチェックを通過します
}
```
